childElements.propertySetConfig:
{
  "label": "Extraordinary Circumstances Present?",
  "helpText": "Check if any of the following apply: designated wilderness, critical habitat, wetlands, floodplains, cultural or historic properties, environmental justice communities, threatened/endangered species. See 40 CFR 1501.4(b). When in doubt, check this box — a coordinator will review.",
  "required": false,
  "controlWidth": 12
}

{
  "label": "Basis",
  "value": "%ScreeningResult:ClassificationBasis%",
  "readOnly": true,
  "controlWidth": 12
}

{
  "label": "Potentially Applicable Categorical Exclusions",
  "helpText": "These are active CE catalog entries for the selected agency. Your coordinator will verify applicability after submission.",
  "text": "%ScreeningResult:LibraryEntries%",
  "controlWidth": 12
}

{
  "label": "Submission Summary",
  "controlWidth": 12,
  "fields": [
    {"label": "Lead Agency",                 "value": "%AgencyAbbr%"},
    {"label": "Project Name",                "value": "%Name%"},
    {"label": "Action Type",                 "value": "%nepa_action_type__c%"},
    {"label": "Sector",                      "value": "%nepa_project_sector__c%"},
    {"label": "Surface Disturbance (ac)",    "value": "%nepa_disturbance_acres__c%"},
    {"label": "Extraordinary Circumstances", "value": "%ExtraordinaryCircumstances%"},
    {"label": "Preliminary Recommendation",  "value": "%ScreeningResult:Recommendation%"}
  ]
}
